refsection.programlisting:
// load the database containing the GDP for 25 countries in the OECD over the period 1963-2003
load(GROCERDIR+'/data/gdpan_oecd.dat');
// retrieve the names of all variables in database
listvar=dblist(GROCERDIR+'/data/gdpan_oecd.dat')
res=BNG_ur('log('+listvar+')','pmax=4','kmax=5','t_order=0','criteria=BIC3')
// Example (taken from BNG_ur_d()) provides the BNG_ur test provides the Moon and Perron test
// for the log of gdp of 25 OECD countries, with individual constants but no trends ('t_order=0'),
// the maximum # of factors allowed set to 5 ('kmax=5'),
// the number of factors determined by the criteria 'BIC' proposed by Bai an Ng ('criteria=BIC3'),
// the maximum number of lags to the ADF regressions set to 4 ('pmax=4').
